import ULThemeCard from "@/components/ULThemeCard";
import ULThemePageLayout from "@/components/ULThemePageLayout";
import { applyAuth0Theme } from "@/utils/theme/themeEngine";
import { applyScreenThemeOverrides } from "@/utils/theme/themeOverrides";

import ConsentActions from "./components/ConsentActions";
import Header from "./components/Header";
import ScopesList from "./components/ScopesList";
import { useConsentManager } from "./hooks/useConsentManager";

// Variables CSS que esta pantalla protege del Dashboard branding.
// Edita estos valores para personalizar el aspecto de la pantalla de consent
// sin afectar las demás pantallas.
const CONSENT_THEME_OVERRIDES = [
  {
    variable: "--ul-theme-page-bg-background-color",
    value: "#803571", // Fondo azul muy claro, diferente al default del dashboard
  },
  {
    variable: "--ul-theme-color-primary-button",
    value: "#2563eb", // Azul de acción para el botón "Autorizar"
  },
];

function ConsentScreen() {
  const { consent, locales } = useConsentManager();

  document.title = locales?.page?.title;

  // 1. Aplica todos los valores de branding del Dashboard
  applyAuth0Theme(consent);

  // 2. Sobreescribe SOLO las variables definidas arriba para esta pantalla
  applyScreenThemeOverrides(CONSENT_THEME_OVERRIDES);

  return (
    <ULThemePageLayout className="theme-universal">
      <ULThemeCard className="w-full max-w-[400px] gap-0">
        <Header />
        <ScopesList />
        <ConsentActions />
      </ULThemeCard>
    </ULThemePageLayout>
  );
}

export default ConsentScreen;
